    72|              {LOCALE_FLAGS[currentLocale] ? (
    73|                <span style={{ display: 'flex', alignItems: 'center', gap: '0.3rem' }}>
    74|                  <img src={LOCALE_FLAGS[currentLocale].flag} alt={currentLocale} style={{ width: '18px', height: '12px', borderRadius: '2px', objectFit: 'cover' }} />
    75|                  {LOCALE_FLAGS[currentLocale].label}
    76|                </span>
